module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

localparam IDLE = 2'b00;
localparam GOT_0 = 2'b01;
localparam GOT_01 = 2'b10;
localparam GOT_010 = 2'b11;

reg [1:0] state;
reg [1:0] next_state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= IDLE;
        data_out <= 1'b0;
    end else begin
        state <= next_state;
        if (state == GOT_010 && data_in == 1'b0) begin
            data_out <= 1'b1;
        end else begin
            data_out <= 1'b0;
        end
    end
end

always @(*) begin
    case (state)
        IDLE: begin
            if (data_in == 1'b1 && ~data_in == 1'b1) begin
                next_state = GOT_0;
            end else begin
                next_state = IDLE;
            end
        end
        GOT_0: begin
            if (~data_in == 1'b1) begin
                next_state = GOT_01;
            end else begin
                next_state = GOT_0;
            end
        end
        GOT_01: begin
            if (data_in == 1'b0) begin
                next_state = GOT_010;
            end else begin
                next_state = IDLE;
            end
        end
        GOT_010: begin
            if (data_in == 1'b1) begin
                next_state = GOT_0;
            end else begin
                next_state = GOT_01;
            end
        end
        default: begin
            next_state = IDLE;
        end
    endcase
end
endmodule
